#include <stdio.h>
#include <stdlib.h>

void swap(char *a, char *b) {
    char temp = *a;
    *a = *b;
    *b = temp;
}

void permute(char *str, int left, int right, char ***perms, int *count) {
    if (left == right) {
        (*count)++;
        (*perms) = realloc((*perms), (*count) * sizeof(char *));
        (*perms)[(*count) - 1] = malloc((right + 1) * sizeof(char));
        strcpy((*perms)[(*count) - 1], str);
    } else {
        for (int i = left; i <= right; i++) {
            swap((str + left), (str + i));
            permute(str, left + 1, right, perms, count);
            swap((str + left), (str + i));
        }
    }
}

char *getPermutation(int n, int k) {
    char *str = malloc((n + 1) * sizeof(char));
    for (int i = 0; i < n; i++) {
        str[i] = '1' + i;
    }
    str[n] = '\0';
    char ***perms = NULL;
    int count = 0;
    permute(str, 0, n - 1, &perms, &count);
    for (int i = 0; i < count - 1; i++) {
        for (int j = i + 1; j < count; j++) {
            if (strcmp(perms[i], perms[j]) > 0) {
                char *temp = perms[i];
                perms[i] = perms[j];
                perms[j] = temp;
            }
        }
    }
    char *result = perms[k - 1];
    for (int i = 0; i < count; i++) {
        free(perms[i]);
    }
    free(perms);
    free(str);
    return result;
}

int main() {
    int n = 3, k = 3;
    char *ans = getPermutation(n, k);
    printf("The Kth permutation sequence is %s\n", ans);
    free(ans);
    return 0;
}

