class Solution {
    // Function to generate all possible permutations of a string
    permutationHelper(s, index, res) {
        if (index === s.length) {
            res.push(s.join(''));
            return;
        }
        for (let i = index; i < s.length; i++) {
            // Swap and recurse
            [s[i], s[index]] = [s[index], s[i]];
            this.permutationHelper(s, index + 1, res);
            [s[i], s[index]] = [s[index], s[i]];  // backtrack
        }
    }

    getPermutation(n, k) {
        let s = Array.from({ length: n }, (_, i) => (i + 1).toString());
        let res = [];

        this.permutationHelper(s, 0, res);  // Generate all permutations
        res.sort();  // Sort the generated permutations

        // Make k 0-based indexed to point to kth sequence
        return res[k - 1];
    }
}

